#' Wrapper function to create an RTMB_Model instance
#'
#' @param data A list of data used for modeling.
#' @param parameters A list (or alist) of parameters.
#' @param model A function or code generated by model_code().
#' @param transformed An optional function OR a list of expressions.
#' @param generate An optional function for generated quantities.
#' @param par_names A list of parameter names.
#' @param init A list or numeric vector of initial values.
#' @param view Character vector specifying the names of parameters to prioritize in the summary.
#' @export
rtmb_model <- function(data, parameters, model,
                       transformed = NULL,
                       generate = NULL,
                       par_names = list(),
                       init = NULL,
                       view = NULL) {

  # 1. parameters への名前の注入
  build_par_list <- function(dat, params) {
    eval_env <- list2env(dat, parent = parent.frame())
    lapply(names(params), function(n) {
      p <- params[[n]]
      if (typeof(p) %in% c("language", "symbol")) {
        eval(p, envir = eval_env)
      } else {
        p
      }
    }) |> setNames(names(params))
  }
  evaluated_par_list <- build_par_list(data, parameters)

  # 2. 実行前のデータ・型チェック
  validate_data(data, evaluated_par_list)

  # 3. transformed と generate の評価
  raw_transformed <- substitute(transformed)
  if (!is.null(raw_transformed) && !is.function(transformed)) {
    transformed <- eval(bquote(transformed_code(.(raw_transformed), env = parent.frame())))
  }

  raw_generate <- substitute(generate)
  if (!is.null(raw_generate) && !is.function(generate)) {
    generate <- eval(bquote(transformed_code(.(raw_generate), env = parent.frame())))
  }

  # 4. モデルの構築とエラーハンドリング
  tryCatch({
    model_instance <- RTMB_Model$new(
      data         = data,
      par_list     = evaluated_par_list,
      log_prob     = model,
      transform    = transformed,
      generate     = generate,
      par_names    = par_names,
      init         = init,
      view         = view
    )
    return(model_instance)
  }, error = function(e) {
    stop("モデルの初期化中にエラーが発生しました。\n", e$message, call. = FALSE)
  })
}
#' Model Code Wrapper for RTMB
#'
#' @param expr A block of code containing model description.
#' @param env Environment to assign to the generated function.
#' @return A standard R function object taking (dat, par).
#' @export
model_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # 修正点1: ユーザーが変数として quote() を渡した場合への対応
  # 例: my_ast <- quote({ Y ~ normal(0,1) }); model_code(my_ast)
  if (is.name(raw_expr)) {
    evaluated <- eval(raw_expr, envir = env)
    if (is.language(evaluated)) {
      raw_expr <- evaluated
    }
  }

  # 式を再帰的に走査し、`~` の記述を書き換える
  rewrite_formula <- function(x) {
    if (is.call(x)) {
      if (identical(x[[1]], as.name("~"))) {
        target <- x[[2]]
        dist_call <- x[[3]]

        # 修正点2: 右辺が関数呼び出しでない場合のエラーハンドリング
        # 例: Y ~ normal （カッコがない）と書かれた場合を防ぐ
        if (!is.call(dist_call)) {
          stop(sprintf("The right side of '~' must be a distribution function call. (e.g., %s( ... ))",
                       as.character(dist_call)), call. = FALSE)
        }

        dist_name <- as.character(dist_call[[1]])
        dist_args <- as.list(dist_call[-1])

        name_lpdf <- paste0(dist_name, "_lpdf")
        name_lpmf <- paste0(dist_name, "_lpmf")

        # 環境に存在する方を優先的に採用
        if (exists(name_lpdf, mode = "function", envir = env)) {
          actual_name <- name_lpdf
        } else if (exists(name_lpmf, mode = "function", envir = env)) {
          actual_name <- name_lpmf
        } else {
          actual_name <- name_lpdf # デフォルト
        }

        # lp <- lp + actual_name(target, args...) の純粋な構文木を作成
        new_call <- as.call(c(
          as.name("<-"),
          as.name("lp"),
          as.call(c(
            as.name("+"),
            as.name("lp"),
            as.call(c(as.name(actual_name), target, dist_args))
          ))
        ))
        return(new_call)
      }
      # 再帰的に要素を書き換え
      x[] <- lapply(x, rewrite_formula)
    }
    return(x)
  }

  processed_expr <- rewrite_formula(raw_expr)

  # ブロック {} の場合は中身を展開してフラットにする
  if (is.call(processed_expr) && identical(processed_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(processed_expr)[-1]
  } else {
    expr_elements <- list(processed_expr)
  }

  # 修正点3: body_list の要素に意図しない名前が付かないよう unname で安全化
  # 関数の中身（ボディ）を構築: { getAll(dat, par); lp <- 0; ... ; return(lp) }
  body_list <- c(
    list(as.name("{")),
    quote(getAll(dat, par)),
    quote(lp <- 0),
    unname(expr_elements),
    quote(return(lp))
  )
  body_expr <- as.call(body_list)

  # 引数リスト `(dat, par)` を作成
  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)

  # 関数の評価（作成）
  log_prob_fn <- eval(fn_expr, envir = env)

  # print_code メソッドなどのために元の構文木を保存
  attr(log_prob_fn, "raw_expr") <- raw_expr

  return(log_prob_fn)
}
#' Transformed Code Wrapper for RTMB
#'
#' @param expr A block of code containing calculations for transformed parameters.
#' @param env Environment to assign to the generated function.
#' @return A function taking (dat, par) that returns a named list.
#' @export
transformed_code <- function(expr, env = parent.frame()) {
  raw_expr <- substitute(expr)

  # 1. 中括弧 {} の中身をフラットにする
  if (is.call(raw_expr) && identical(raw_expr[[1]], as.name("{"))) {
    expr_elements <- as.list(raw_expr)[-1]
  } else {
    expr_elements <- list(raw_expr)
  }

  # 2. 最後の要素が出力として明示されているか判定
  last_elem <- expr_elements[[length(expr_elements)]]

  is_explicit_return <- FALSE
  if (is.call(last_elem)) {
    if (identical(last_elem[[1]], as.name("list"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem
    } else if (identical(last_elem[[1]], as.name("return"))) {
      is_explicit_return <- TRUE
      ret_call <- last_elem[[2]]
    }
  } else if (is.name(last_elem)) {
    is_explicit_return <- TRUE
    ret_call <- last_elem
  }

  if (is_explicit_return) {
    # 明示的に出力が指定されている場合、それを出力として採用
    # 重複評価を防ぐため、通常の実行フローから最後の要素を削除
    expr_elements <- expr_elements[-length(expr_elements)]

  } else {
    # 記述がない場合は従来通り自動抽出する
    find_assignments <- function(x) {
      if (is.call(x)) {
        if (identical(x[[1]], as.name("<-")) || identical(x[[1]], as.name("="))) {
          if (is.name(x[[2]])) return(as.character(x[[2]]))
        }
        return(unique(unlist(lapply(as.list(x), find_assignments))))
      }
      return(NULL)
    }
    defined_vars <- find_assignments(raw_expr)
    ret_list_args <- lapply(defined_vars, as.name)
    names(ret_list_args) <- defined_vars
    ret_call <- as.call(c(list(as.name("list")), ret_list_args))
  }

  # 3. 関数ボディの構築
  body_list <- c(
    list(as.name("{")),
    quote(getAll(dat, par)),
    unname(expr_elements),
    list(as.call(list(as.name("return"), ret_call)))
  )
  body_expr <- as.call(body_list)

  # 4. 関数オブジェクトの生成
  args <- as.pairlist(alist(dat = , par = ))
  fn_expr <- call("function", args, body_expr)
  fn <- eval(fn_expr, envir = env)
  attr(fn, "raw_expr") <- raw_expr

  return(fn)
}
#' データとパラメータの事前検証
#'
#' @description
#' `rtmb_model` にデータを渡す前に、R特有のデータ型（data.frameなど）が混入していないか、
#' および欠損値の有無などをチェックし、エラーや警告を出力します。
#'
#' @param dat_list モデルに渡すデータのリスト（通常、行列や数値ベクトルを含む）。
#' @param par_list `Dim()` で定義されたパラメータのリスト。
#'
#' @return 検証に成功した場合は不可視の `NULL` を返します。問題がある場合は `stop()` で処理を中断、または `warning()` を発出します。
#'
#' @details
#' RTMBの自動微分エンジンは純粋な `matrix` や `numeric` を要求します。
#' ユーザーが誤って `data.frame` を渡した場合、計算グラフの構築時に不可解なエラーが発生するため、
#' この関数で事前に捕捉します。
validate_data <- function(dat_list, par_list) {
  # 1. データフレームのチェック
  for (name in names(dat_list)) {
    if (is.data.frame(dat_list[[name]])) {
      stop(sprintf(
        "【エラー】データ '%s' がデータフレーム(data.frame)のまま渡されています。\n行列演算が失敗するため、as.matrix() で行列に変換してから渡してください。",
        name
      ), call. = FALSE)
    }
  }

  # 2. NAのチェック
  for (name in names(dat_list)) {
    if (any(is.na(dat_list[[name]]))) {
      warning(sprintf("【警告】データ '%s' に欠損値(NA)が含まれています。予期せぬ動作を引き起こす可能性があります。", name), call. = FALSE)
    }
  }

  invisible(NULL)
}


#' 安全なRTMBモデルの構築（エラーメッセージ翻訳付き）
#'
#' @description
#' `rtmb_model` をラップし、内部の `MakeADFun` 実行時に発生する C++/RTMB 由来の
#' 難解なエラーメッセージを、ユーザーが理解しやすい日本語のヒントに翻訳して出力します。
#'
#' @param data `validate_data` を通過したデータのリスト。
#' @param parameters `Dim()` で定義されたパラメータのリスト。
#' @param model `model_code({})` で定義された尤度や事前分布のコードブロック。
#' @param generate `transformed_code({})` で定義された生成量のコードブロック（省略可能）。
#'
#' @return 正常にコンパイルが完了した場合は、`rtmb_model` オブジェクト（R6クラスのインスタンス）を返します。
#'
#' @export
safe_rtmb_model <- function(data, parameters, model, generate = NULL) {
  # 事前検証を実行
  validate_data(data, parameters)

  tryCatch({
    # 実際のモデル構築処理
    obj <- rtmb_model(data, parameters, model, generate)
    return(obj)

  }, error = function(e) {
    err_msg <- conditionMessage(e)

    # ADクラス消失エラーの翻訳
    if (grepl("lost class attribute", err_msg) || grepl("Invalid argument to 'advector'", err_msg)) {
      stop(
        "【モデル構築エラー】自動微分(AD)の型が途中で消失しました。\n",
        "・原因: model_code 内で rep() や空の array() に対して for ループで逐次代入を行っている可能性があります。\n",
        "・対策: 行列のベクトル化計算を使用するか、初期化には numeric(M) などを利用してください。\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 不正な演算エラーの翻訳
    if (grepl("illegal operation", err_msg) || grepl("not a valid 'advector'", err_msg)) {
      stop(
        "【モデル構築エラー】実行不可能な演算、または型の不整合が発生しました。\n",
        "・原因: 行列の掛け算(%*%)の左右で次元が合っていない、または Dim() の型指定 (CF_cov, lower_tri など) が実際の行列サイズと矛盾している可能性があります。\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 数値/行列型エラーの翻訳
    if (grepl("requires numeric/complex matrix/vector", err_msg)) {
      stop(
        "【データ型エラー】数値ベクトルまたは行列が必要な箇所に、別の型が渡されています。\n",
        "・原因: 観測データやインデックスが data.frame や list になっていませんか？\n",
        "[元のエラー]: ", err_msg,
        call. = FALSE
      )
    }

    # 未知のエラーはそのまま出力
    stop("【予期せぬエラー】\n", err_msg, call. = FALSE)
  })
}


#' RTMBベースのGLMMラッパー関数
#' @param formula lme4スタイルのフォーミュラ (例: Y ~ X + (1 + X | GID))
#' @param data データフレーム
#' @param family 分布族の文字列
#' @param laplace 変量効果をラプラス近似で周辺化するかどうか (デフォルト: FALSE)
#' @param prior 事前分布のハイパーパラメータのリスト
#' @param init 初期値のリスト (指定しない場合はglmに基づく初期値が自動生成されます)
#' @export
rtmb_glmer <- function(formula, data, family = "gaussian", laplace = FALSE,
                       prior = list(
                         beta_sd = 10,
                         tau_rate = 1,
                         sigma_rate = 1,
                         lkj_eta = 1.0,
                         shape_rate = 1,
                         phi_rate = 1,
                         cutpoint_sd = 2.5
                       ),
                       init = NULL) {

  if (!requireNamespace("lme4", quietly = TRUE)) {
    stop("フォーミュラの解析に 'lme4' パッケージが必要です。")
  }

  # 1. フォーミュラのパース
  parsed <- lme4::lFormula(
    formula,
    data = data,
    control = lme4::lmerControl(
      check.nobs.vs.nlev = "ignore",
      check.nobs.vs.nRE  = "ignore"
    )
  )

  # --- 応答変数Yの型変換（factor型・行列型への対応） ---
  Y <- model.response(parsed$fr)
  if (is.matrix(Y)) {
    if (ncol(Y) == 2 && family == "binomial") {
      trials <- as.numeric(Y[, 1] + Y[, 2])
      Y <- as.numeric(Y[, 1])
    } else if (ncol(Y) == 1) {
      Y <- as.numeric(Y[, 1])
      trials <- rep(1, length(Y))
    } else {
      stop("応答変数の行列形式が不正です。binomialの場合は cbind(成功数, 失敗数) を指定してください。")
    }
  } else {
    trials <- rep(1, length(Y))
    if (is.factor(Y)) {
      if (family %in% c("bernoulli", "binomial")) {
        Y <- as.numeric(Y) - 1
      } else {
        Y <- as.numeric(Y)
      }
    } else {
      Y <- as.numeric(Y)
    }
  }

  X <- parsed$X          # 固定効果のデザイン行列
  reTrms <- parsed$reTrms

  if (length(reTrms$Ztlist) > 1) {
    stop("現在、ラッパー関数は単一のグループ化変数のみに対応しています。")
  }

  if (family == "ordered" && "(Intercept)" %in% colnames(X)) {
    X <- X[, colnames(X) != "(Intercept)", drop = FALSE]
    if (ncol(X) == 0) {
      stop("順序ロジスティックモデル(family='ordered')では切片のみのモデルは現在サポートされていません。少なくとも1つの説明変数を指定してください。")
    }
  }

  # 固定効果と変量効果の名前を取得
  fixed_names <- colnames(X)
  fixed_names[fixed_names == "(Intercept)"] <- "Intercept"
  ranef_names <- parsed$reTrms$cnms[[1]]
  ranef_names[ranef_names == "(Intercept)"] <- "Intercept"

  # 変量効果の情報の抽出
  Zt <- as.matrix(reTrms$Ztlist[[1]])
  group_idx <- as.integer(reTrms$flist[[1]])
  num_groups <- length(levels(reTrms$flist[[1]]))
  num_ranef <- nrow(Zt) / num_groups

  # オフセット項の抽出
  offset <- model.offset(parsed$fr)

  # --- スマート初期化 (glmの利用) ---
  if (is.null(init)) {
    tryCatch({
      # 変量効果項を削除し、固定効果のみのフォーミュラにする
      # (lme4のアップデートに伴うパッケージ移行への対応)
      if (requireNamespace("reformulas", quietly = TRUE)) {
        fixed_formula <- reformulas::nobars(formula)
      } else {
        fixed_formula <- suppressWarnings(lme4::nobars(formula))
      }

      # glmのfamilyを近似的に設定
      glm_fam <- switch(family,
                        "gaussian" = gaussian(),
                        "student_t" = gaussian(),
                        "lognormal" = gaussian(link = "log"),
                        "bernoulli" = binomial(),
                        "binomial" = binomial(),
                        "poisson" = poisson(),
                        "neg_binomial" = poisson(), # 近似としてpoissonを使用
                        "gamma" = Gamma(link = "log"),
                        gaussian()
      )

      # ordered などの場合はglmが失敗して tryCatch で NULL にフォールバックする
      fit_glm <- suppressWarnings(glm(fixed_formula, data = data, family = glm_fam))

      # 係数を取得し、NA（多重共線性などで生じる）を0で埋める
      init_b <- unname(coef(fit_glm))
      init_b[is.na(init_b)] <- 0

      # partial initialization の恩恵で、b 以外は自動的にランダム初期化される
      init <- list(b = init_b)

    }, error = function(e) {
      init <- NULL
    })
  }

  # 観測ごとの変量効果デザイン行列(N x num_ranef)を作成
  N <- length(Y)
  Z_mat <- matrix(0, nrow = N, ncol = num_ranef)
  for (i in 1:N) {
    g <- group_idx[i]
    rows <- ((g - 1) * num_ranef + 1):(g * num_ranef)
    Z_mat[i, ] <- Zt[rows, i]
  }

  # 2. dataの準備
  dat <- list(
    N = N,
    Y = Y,
    trials = trials,
    X = X,
    offset = offset,
    Z_mat = Z_mat,
    group_idx = group_idx,
    num_groups = num_groups,
    num_ranef = num_ranef,
    K = ncol(X),
    fam_name = family,
    prior_beta_sd    = prior$beta_sd,
    prior_tau_rate   = prior$tau_rate,
    prior_sigma_rate = prior$sigma_rate,
    prior_lkj_eta    = prior$lkj_eta,
    prior_shape_rate = prior$shape_rate,
    prior_phi_rate   = prior$phi_rate,
    prior_cutpoint_sd = prior$cutpoint_sd
  )

  # parameterの準備
  if (num_ranef == 1) {
    params <- list(
      b  = Dim(ncol(X)),
      sd = Dim(num_ranef, lower = 0),
      r  = Dim(num_groups, random = TRUE)
    )
  } else {
    params <- list(
      b      = Dim(ncol(X)),
      sd     = Dim(num_ranef, lower = 0),
      CF_cor = Dim(c(num_ranef, num_ranef), type = "CF_corr"),
      r      = Dim(c(num_groups, num_ranef), random = TRUE)
    )
  }

  # 分布族に応じた追加パラメータの設定
  if (family %in% c("gaussian", "lognormal", "student_t")) {
    params$sigma <- Dim(1, lower = 0)
  }
  if (family == "student_t") {
    params$nu <- Dim(1, lower = 2)
  }
  if (family == "gamma") {
    params$shape <- Dim(1, lower = 0)
  }
  if (family == "neg_binomial") {
    params$phi <- Dim(1, lower = 0)
  }
  if (family == "ordered") {
    num_categories <- length(unique(Y))
    params$cutpoints <- Dim(num_categories - 1, type = "ordered")
  }

  # 3. モデルコードの動的構築
  ll_expr <- switch(family,
                    "gaussian" = quote({
                      sigma ~ exponential(prior_sigma_rate)
                      Y ~ normal(eta, sigma)
                    }),
                    "lognormal" = quote({
                      sigma ~ exponential(prior_sigma_rate)
                      Y ~ lognormal(eta, sigma)
                    }),
                    "student_t" = quote({
                      sigma ~ exponential(prior_sigma_rate)
                      nu ~ exponential(0.1)
                      Y ~ student_t(nu, eta, sigma)
                    }),
                    "gamma" = quote({
                      shape ~ exponential(prior_shape_rate)
                      Y ~ gamma(shape, shape / exp(eta))
                    }),
                    "bernoulli" = quote({
                      Y ~ bernoulli_logit(eta)
                    }),
                    "binomial" = quote({
                      Y ~ binomial_logit(trials, eta)
                    }),
                    "poisson" = quote({
                      Y ~ poisson(exp(eta))
                    }),
                    "neg_binomial" = quote({
                      phi ~ exponential(prior_phi_rate)
                      Y ~ neg_binomial_2(exp(eta), phi)
                    }),
                    "ordered" = quote({
                      Y ~ ordered_logistic(eta, cutpoints)
                      cutpoints ~ normal(0, prior_cutpoint_sd)
                    })
  )

  if (num_ranef > 1) {
    common_expr <- quote({
      # 事前分布
      b ~ normal(0, prior_beta_sd)
      sd ~ exponential(prior_tau_rate)
      CF_cor ~ lkj_CF_corr(prior_lkj_eta)

      # 変量効果の事前分布
      for (j in 1:num_groups) {
        r[j, ] ~ multi_normal_CF(rep(0, num_ranef), rep(1, num_ranef), CF_cor)
      }

      # 線形予測子の計算
      eta <- X %*% b
      for (i in 1:N) {
        eta[i] <- eta[i] + sum(Z_mat[i, ] * r[group_idx[i], ] * sd)
      }
    })
  } else {
    common_expr <- quote({
      # 事前分布
      b ~ normal(0, prior_beta_sd)
      sd ~ exponential(prior_tau_rate)

      # 変量効果の事前分布
      r ~ normal(0, 1)

      # 線形予測子の計算
      eta <- X %*% b + Z_mat[,1] * r[group_idx] * sd
    })
  }

  if (!is.null(offset)) {
    offset_expr <- quote({eta <- eta + offset})
  } else {
    offset_expr <- quote({})
  }

  common_list <- as.list(common_expr)[-1]
  ll_list <- as.list(ll_expr)[-1]
  offset_list <- as.list(offset_expr)[-1]

  model_ast <- as.call(c(list(as.name("{")), common_list, offset_list, ll_list))
  model_expr <- eval(bquote(model_code(.(model_ast))))

  # 4. 相関行列を transform で構築
  if (num_ranef > 1) {
    tran_expr <- transformed_code({
      cor <- CF_cor %*% t(CF_cor)
    })
  } else {
    tran_expr <- NULL
  }

  # 5. rtmb_model を呼び出してオブジェクトを返す
  if (num_ranef > 1) {
    obj <- rtmb_model(
      data = dat,
      parameters = params,
      model = model_expr,
      transformed = tran_expr,
      generate = NULL,
      par_names = list(b = fixed_names, sd = ranef_names, cor = ranef_names),
      init = init,
      view = c("b", "sd", "cor")
    )
  } else {
    obj <- rtmb_model(
      data = dat,
      parameters = params,
      model = model_expr,
      par_names = list(b = fixed_names, sd = ranef_names),
      init = init,
      view = c("b", "sd", "cor")
    )
  }

  obj$formula <- formula
  obj$raw_data <- data
  obj$family <- family

  return(obj)
}
#' RTMBベースのGLMラッパー関数 (変量効果なし)
#'
#' @param formula フォーミュラ (例: Y ~ X1 + X2)
#' @param data データフレーム
#' @param family 分布族の文字列
#' @param prior 事前分布のハイパーパラメータのリスト
#' @export
rtmb_glm <- function(formula, data, family = "gaussian",
                     prior = list(
                       beta_sd = 10,
                       sigma_rate = 1,
                       shape_rate = 1,
                       phi_rate = 1,
                       cutpoint_sd = 2.5
                     )) {

  # 1. フォーミュラのパース
  mf <- model.frame(formula, data)
  Y <- model.response(mf)
  X <- model.matrix(formula, mf)

  if (family == "ordered" && "(Intercept)" %in% colnames(X)) {
    X <- X[, colnames(X) != "(Intercept)", drop = FALSE]
    if (ncol(X) == 0) {
      stop("順序ロジスティックモデル(family='ordered')では切片のみのモデルは現在サポートされていません。少なくとも1つの説明変数を指定してください。")
    }
  }

  if (is.matrix(Y)) {
    if (ncol(Y) == 2 && family == "binomial") {
      trials <- as.numeric(Y[, 1] + Y[, 2])
      Y <- as.numeric(Y[, 1])
    } else if (ncol(Y) == 1) {
      Y <- as.numeric(Y[, 1])
      trials <- rep(1, length(Y))
    } else {
      stop("応答変数の行列形式が不正です。binomialの場合は cbind(成功数, 失敗数) を指定してください。")
    }
  } else {
    trials <- rep(1, length(Y))
    if (is.factor(Y)) {
      if (family %in% c("bernoulli", "binomial")) {
        Y <- as.numeric(Y) - 1
      } else {
        Y <- as.numeric(Y)
      }
    } else {
      Y <- as.numeric(Y)
    }
  }

  N <- length(Y)
  fixed_names <- colnames(X)
  fixed_names[fixed_names == "(Intercept)"] <- "Intercept"

  offset <- model.offset(mf)

  # 2. dataの準備
  dat <- list(
    N = N,
    Y = Y,
    trials = trials,
    X = X,
    offset = offset,
    K = ncol(X),
    prior_beta_sd     = prior$beta_sd,
    prior_sigma_rate  = prior$sigma_rate,
    prior_shape_rate  = prior$shape_rate,
    prior_phi_rate    = prior$phi_rate,
    prior_cutpoint_sd = prior$cutpoint_sd
  )

  # 3. parameterの準備 (固定効果 b に変更)
  params <- list(
    b = Dim(ncol(X))
  )

  if (family %in% c("gaussian", "lognormal", "student_t")) {
    params$sigma <- Dim(1, lower = 0)
  }
  if (family == "student_t") {
    params$nu <- Dim(1, lower = 2)
  }
  if (family == "gamma") {
    params$shape <- Dim(1, lower = 0)
  }
  if (family == "neg_binomial") {
    params$phi <- Dim(1, lower = 0)
  }
  if (family == "ordered") {
    num_categories <- length(unique(Y))
    params$cutpoints <- Dim(num_categories - 1, type = "ordered")
  }

  # 4. モデルコードの動的構築
  ll_expr <- switch(family,
                    "gaussian" = quote({
                      Y ~ normal(eta, sigma)
                      sigma ~ exponential(prior_sigma_rate)
                    }),
                    "lognormal" = quote({
                      Y ~ lognormal(eta, sigma)
                      sigma ~ exponential(prior_sigma_rate)
                    }),
                    "student_t" = quote({
                      Y ~ student_t(nu, eta, sigma)
                      sigma ~ exponential(prior_sigma_rate)
                      nu ~ exponential(0.1)
                    }),
                    "gamma" = quote({
                      Y ~ gamma(shape, shape / exp(eta))
                      shape ~ exponential(prior_shape_rate)
                    }),
                    "bernoulli" = quote({
                      Y ~ bernoulli_logit(eta)
                    }),
                    "binomial" = quote({
                      Y ~ binomial_logit(trials, eta)
                    }),
                    "poisson" = quote({
                      Y ~ poisson(exp(eta))
                    }),
                    "neg_binomial" = quote({
                      Y ~ neg_binomial_2(exp(eta), phi)
                      phi ~ exponential(prior_phi_rate)
                    }),
                    "ordered" = quote({
                      Y ~ ordered_logistic(eta, cutpoints)
                      cutpoints ~ normal(0, prior_cutpoint_sd)
                    })
  )

  # b を用いて計算
  common_expr <- quote({
    b ~ normal(0, prior_beta_sd)
    eta <- as.vector(X %*% b)
  })

  if (!is.null(offset)) {
    offset_expr <- quote({eta <- eta + offset})
  } else {
    offset_expr <- quote({})
  }

  common_list <- as.list(common_expr)[-1]
  ll_list <- as.list(ll_expr)[-1]
  offset_list <- as.list(offset_expr)[-1]

  model_ast <- as.call(c(list(as.name("{")), common_list, offset_list, ll_list))
  model_expr <- eval(bquote(model_code(.(model_ast))))

  # 5. rtmb_model を呼び出してオブジェクトを返す
  obj <- rtmb_model(
    data = dat,
    parameters = params,
    model = model_expr,
    generate = NULL,
    par_names = list(b = fixed_names)
  )

  obj$formula <- formula
  obj$raw_data <- data
  obj$family <- family

  return(obj)
}
#' 探索的因子分析 (Bayesian EFA) 安定・潜在変数モデル版ラッパー
#'
#' @param data 観測データフレームまたは行列 (N x P)
#' @param n_factors 因子の数 (K)
#' @param rotate 回転方法の文字列 (例: "varimax", "promax")。NULLの場合は回転しない。
#' @param score 論理値; TRUEの場合、generateブロックで因子得点を計算する (デフォルトはFALSE)
#' @param prior 事前分布のハイパーパラメータのリスト
#' @param init 初期値のリスト (指定しない場合はPCAに基づく初期値が自動生成されます)
#' @export
rtmb_fa <- function(data, nfactors = 1, rotate = NULL, score = FALSE,
                    prior = list(mu_sd = 10, lambda_sd = 1, psi_rate = 10),
                    init = NULL) {

  Y <- as.matrix(data)
  N <- nrow(Y)
  J <- ncol(Y)
  K <- nfactors

  var_names <- colnames(data)
  if (is.null(var_names)) var_names <- paste0("V", 1:J)

  if (K >= J) {
    stop("因子の数(K)は観測変数の数(J)より小さくする必要があります。")
  }

  # --- データの準備 (十分統計量) ---
  Y_bar <- apply(Y, 2, mean)
  S_Y <- cov(Y) * (N - 1)

  dat_fa <- list(
    N       = N,
    J       = J,
    Y_bar   = Y_bar,
    S_Y     = S_Y,
    prior_mu_sd     = prior$mu_sd,
    prior_lambda_sd = prior$lambda_sd,
    prior_psi_rate  = prior$psi_rate
  )

  # スコアを計算する場合のみ、生のデータ行列 Y を渡す
  if (score) {
    dat_fa$Y <- Y
  }

  # --- パラメータ定義 ---
  par_fa <- list(
    mu     = Dim(dim = J),
    Lambda = Dim(dim = c(J, K), type = "lower_tri"),
    psi    = Dim(dim = J, lower = 0)
  )

  # --- スマート初期化 (PCA) ---
  if (is.null(init)) {
    tryCatch({
      eig <- eigen(S_Y / (N - 1))
      L_pca <- eig$vectors[, 1:K, drop = FALSE] %*% diag(sqrt(eig$values[1:K]), nrow=K, ncol=K)
      L_top <- L_pca[1:K, , drop = FALSE]
      qr_res <- qr(t(L_top))
      Q_mat <- qr.Q(qr_res)
      init_Lambda <- L_pca %*% Q_mat

      # 負の値によるNaNを防ぐため pmax で 0.01 でクリップ
      init_psi <- pmax(diag(S_Y / (N - 1)) - rowSums(init_Lambda^2), 0.01)^0.5

      # lower_triの制約（上三角をゼロ）
      for (j in 1:J) {
        for (k in 1:K) {
          if (j < k) init_Lambda[j, k] <- 0
        }
      }

      init <- list(
        mu     = Y_bar,
        Lambda = init_Lambda,
        psi    = init_psi
      )
    }, error = function(e) {
      init <- NULL
    })
  }

  # --- モデルコードの構築 ---
  model_expr <- model_code({
    S_Y ~ sufficient_multi_normal_fa(N, Y_bar, mu, psi, Lambda)
    mu ~ normal(0, prior_mu_sd)
    psi ~ exponential(prior_psi_rate)
    Lambda ~ lower_tri_normal(0, prior_lambda_sd)
  })

  # --- 生成量 (GQ) のコードをASTで動的構築 ---
  base_gq <- quote({
    Sigma <- Lambda %*% t(Lambda) + diag(psi^2)
    var_total <- diag(Sigma)
    var_common <- rowSums(Lambda^2)
    communality <- var_common / var_total
    out <- list(communality = communality)
  })

  if (!is.null(rotate)) {
    rot_loadings_name <- paste0("Lambda_", rotate)

    rot_expr <- bquote({
      rot_fn <- getExportedValue("GPArotation", .(rotate))
      rot_obj <- rot_fn(Lambda)
      out[[.(rot_loadings_name)]] <- rot_obj$loadings

      if (!is.null(rot_obj$Phi)) {
        out$fa_cor <- rot_obj$Phi
      }
    })

    score_expr <- if (score) {
      quote({
        # 観測データの中心化
        Y_c <- matrix(0, nrow = N, ncol = J)
        for (i in 1:N) Y_c[i, ] <- Y[i, ] - mu

        # 回帰法によるスコアの計算 (斜交回転の場合はPhiを考慮)
        if (!is.null(rot_obj$Phi)) {
          out$score <- Y_c %*% solve(Sigma, rot_obj$loadings %*% rot_obj$Phi)
        } else {
          out$score <- Y_c %*% solve(Sigma, rot_obj$loadings)
        }
      })
    } else quote({})

  } else {
    rot_expr <- quote({})

    score_expr <- if (score) {
      quote({
        # 観測データの中心化
        Y_c <- matrix(0, nrow = N, ncol = J)
        for (i in 1:N) Y_c[i, ] <- Y[i, ] - mu

        # 回帰法によるスコアの計算 (未回転)
        out$score <- Y_c %*% solve(Sigma, Lambda)
      })
    } else quote({})
  }

  ret_expr <- quote({ return(out) })

  # 構文木 (AST) を1つのブロックに結合
  gq_ast <- as.call(c(list(as.name("{")),
                      as.list(base_gq)[-1],
                      as.list(rot_expr)[-1],
                      as.list(score_expr)[-1],
                      as.list(ret_expr)[-1]))

  gq_expr <- eval(bquote(transformed_code(.(gq_ast))))

  # --- パラメータ名の設定 ---
  p_names <- list(
    mu           = var_names,
    Lambda       = var_names,
    psi          = var_names,
    communality  = var_names
  )

  if (!is.null(rotate)) {
    p_names[[paste0("Lambda_", rotate)]] <- var_names
    p_names[["fa_cor"]] <- paste0("Factor", 1:K)
  }

  if (score) {
    # score の次元 (N x K) に合わせた名前を設定
    ind_names <- rownames(data)
    if (is.null(ind_names)) ind_names <- paste0("Id", 1:N)
    fac_names <- paste0("Factor", 1:K)
    p_names[["score"]] <- list(ind_names, fac_names)
  }

  # --- view の設定 ---
  target_view <- if (!is.null(rotate)) {
    c(paste0("Lambda_", rotate), "psi")
  } else {
    c("Lambda", "psi")
  }

  # --- モデルオブジェクトの生成 ---
  obj <- rtmb_model(
    data       = dat_fa,
    parameters = par_fa,
    model      = model_expr,
    generate   = gq_expr,
    par_names  = p_names,
    init       = init
  )

  return(obj)
}
#' 相関行列 (多変量正規分布) 推定ラッパー
#'
#' @param data 観測データフレームまたは行列 (N x P)
#' @param prior 事前分布のハイパーパラメータのリスト
#' @export
rtmb_cor <- function(data, prior = list(lkj_eta = 1.0, mu_sd = 10, sigma_rate = 1.0)) {

  Y <- as.matrix(data)
  N <- nrow(Y)
  P <- ncol(Y)

  var_names <- colnames(data)
  if (is.null(var_names)) var_names <- paste0("V", 1:P)

  dat <- list(
    N = N,
    P = P,
    Y = Y,
    prior_lkj_eta    = prior$lkj_eta,
    prior_sigma_rate = prior$sigma_rate,
    prior_mu_sd      = prior$mu_sd
  )

  params <- list(
    mean   = Dim(P),
    sd     = Dim(P, lower = 0),
    CF_cor = Dim(c(P, P), type = "CF_corr") # corに統一
  )

  model_expr <- model_code({
    # 事前分布
    mean ~ normal(0, prior_mu_sd)
    sd ~ exponential(prior_sigma_rate)
    CF_cor ~ lkj_CF_corr(prior_lkj_eta)

    for(i in 1:N) {
      Y[i, ] ~ multi_normal_CF(mean, sd, CF_cor)
    }
  })

  # transformでcorを計算
  tran_expr <- transformed_code({
    cor <- CF_cor %*% t(CF_cor)
  })

  obj <- rtmb_model(
    data        = dat,
    parameters  = params,
    model       = model_expr,
    transformed = tran_expr,
    generate    = NULL,
    par_names   = list(mean = var_names, sd = var_names, cor = var_names),
    view        = c("cor")
  )

  return(obj)
}
